import { useState } from "react";
import { Card, SectionTitle, PageTitle, ErrBox, DropZone, Btn, Input, Tag, Ic, ICONS } from "../components/UI";

const Analyzer = ({ t, toast }) => {
  const [file, setFile]     = useState(null);
  const [loading, setLoad]  = useState(false);
  const [result, setResult] = useState(null);
  const [err, setErr]       = useState(null);
  const [q, setQ]           = useState("");
  const [qaLoad, setQaLoad] = useState(false);
  const [ans, setAns]       = useState(null);

  const run = async () => {
    setLoad(true); setErr(null); setResult(null);
    try {
      const fd = new FormData(); fd.append("file", file);
      const r = await fetch("http://localhost:8001/api/analyze", { method: "POST", body: fd });
      if (!r.ok) throw new Error(`Server error ${r.status}`);
      setResult(await r.json());
      toast("Analysis complete", "success");
    } catch (e) { setErr(e.message); toast(e.message, "error"); }
    finally { setLoad(false); }
  };

  const ask = async () => {
    if (!q || !result?.session_id) return;
    setQaLoad(true); setAns(null);
    try {
      const r = await fetch("http://localhost:8001/api/qa", {
        method: "POST", headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ question: q, session_id: result.session_id }),
      });
      setAns((await r.json()).answer);
    } catch (e) { toast("QA failed: " + e.message, "error"); }
    finally { setQaLoad(false); }
  };

  const getVariant = (level) =>
    level === "Safe"      ? "success" :
    level === "Caution"   ? "warning" :
    level === "High Risk" || level === "Illegal" ? "danger" : "warning";

  const getColor = (variant) => ({ success: t.green, warning: t.amber, danger: t.red })[variant];

  return (
    <div style={{ maxWidth: 820, margin: "0 auto", padding: "52px 24px" }}>
      <PageTitle
        icon="doc"
        title="Document Analyzer"
        desc="Upload a PDF or image. The model reads every clause and flags risk — Safe, Caution, High Risk, or Illegal."
        t={t}
      />

      <Card t={t} style={{ marginBottom: 20 }}>
        <DropZone onFile={setFile} accept=".pdf,.png,.jpg,.jpeg"
          hint="PDF, PNG, or JPEG — contract, FIR, notice, loan doc" t={t} />
        <div style={{ marginTop: 14 }}>
          <Btn onClick={run} disabled={!file || loading} loading={loading} t={t}>
            {loading ? "Analyzing…" : "Run Analysis"}
          </Btn>
        </div>
      </Card>

      {err && <ErrBox msg={err} t={t} />}

      {result && (
        <>
          {/* Summary */}
          <Card t={t} style={{ marginBottom: 16 }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 14 }}>
              <SectionTitle t={t}>Summary</SectionTitle>
              <div style={{ display: "flex", gap: 8 }}>
                {result.document_type && <Tag label={result.document_type} variant="info" t={t} />}
                {result.overall_risk  && (
                  <Tag
                    label={result.overall_risk}
                    variant={result.overall_risk === "Safe" ? "success" : result.overall_risk === "Moderate" ? "warning" : "danger"}
                    t={t}
                  />
                )}
              </div>
            </div>

            <p style={{ color: t.sub, lineHeight: 1.75, margin: "0 0 16px", fontSize: 14 }}>
              {result.summary || "No summary returned."}
            </p>

            {/* Risk distribution */}
            {result.risk_distribution && (
              <div style={{ marginBottom: 12 }}>
                <p style={{ fontSize: 11, color: t.muted, fontWeight: 700, textTransform: "uppercase", letterSpacing: "0.06em", margin: "0 0 8px" }}>
                  Risk breakdown
                </p>
                <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
                  {Object.entries(result.risk_distribution).map(([level, count]) =>
                    count > 0 && <Tag key={level} label={`${level}: ${count}`} variant={getVariant(level)} t={t} />
                  )}
                </div>
              </div>
            )}

            {/* Recommendations */}
            {result.recommendations?.length > 0 && (
              <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
                {result.recommendations.map((rec, i) => (
                  <p key={i} style={{ fontSize: 13, color: t.sub, margin: 0, lineHeight: 1.6 }}>{rec}</p>
                ))}
              </div>
            )}
          </Card>

          {/* Clauses */}
          {result.clauses?.length > 0 && (
            <Card t={t} style={{ marginBottom: 16 }}>
              <SectionTitle t={t}>Clauses — {result.clauses.length} found</SectionTitle>
              <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
                {result.clauses.map((cl, i) => {
                  // ✅ backend returns clause_text (not text)
                  const clauseText = cl.clause_text || cl.text || "";
                  const hasText    = clauseText.trim().length > 10;
                  const variant    = getVariant(cl.risk_level);
                  const color      = getColor(variant);
                  const scorePct   = Math.round((cl.risk_score || 0) * 100);

                  return (
                    <div key={i} style={{ borderRadius: 8, border: `1px solid ${t.border}`, background: t.surfaceUp, overflow: "hidden" }}>

                      {/* Header */}
                      <div style={{
                        display: "flex", justifyContent: "space-between", alignItems: "center",
                        padding: "10px 14px", borderBottom: `1px solid ${t.border}`, background: t.surface,
                      }}>
                        <span style={{ fontSize: 11, color: t.muted, fontWeight: 700, textTransform: "uppercase", letterSpacing: "0.05em" }}>
                          Clause {i + 1}
                        </span>
                        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                          <div style={{ display: "flex", alignItems: "center", gap: 5 }}>
                            <div style={{ width: 56, height: 3, borderRadius: 2, background: t.border, overflow: "hidden" }}>
                              <div style={{ width: `${scorePct}%`, height: "100%", background: color }} />
                            </div>
                            <span style={{ fontSize: 10, color: t.muted }}>{scorePct}%</span>
                          </div>
                          <Tag label={cl.risk_level || "Unclassified"} variant={variant} t={t} />
                        </div>
                      </div>

                      <div style={{ padding: "14px 16px", display: "flex", flexDirection: "column", gap: 10 }}>

                        {/* Clause text from the document */}
                        {hasText ? (
                          <p style={{
                            color: t.text, fontSize: 13, margin: 0, lineHeight: 1.75,
                            padding: "10px 12px", background: t.bg, borderRadius: 6,
                            borderLeft: `3px solid ${color}`,
                          }}>
                            {clauseText}
                          </p>
                        ) : (
                          <p style={{ color: t.muted, fontSize: 13, margin: 0, fontStyle: "italic" }}>
                            Text could not be extracted from this section.
                          </p>
                        )}

                        {/* Why flagged */}
                        {cl.explanation && (
                          <div style={{ padding: "10px 12px", borderRadius: 6, background: `${color}12`, border: `1px solid ${color}30` }}>
                            <p style={{ fontSize: 10, fontWeight: 700, color: color, textTransform: "uppercase", letterSpacing: "0.06em", margin: "0 0 4px" }}>
                              Why flagged
                            </p>
                            <p style={{ color: t.sub, fontSize: 13, margin: 0, lineHeight: 1.6 }}>
                              {cl.explanation}
                            </p>
                          </div>
                        )}

                        {/* What to do */}
                        {cl.suggestion && (
                          <div style={{
                            padding: "10px 12px", borderRadius: 6,
                            background: t.surface, border: `1px solid ${t.border}`,
                            display: "flex", gap: 8, alignItems: "flex-start",
                          }}>
                            <span style={{ fontSize: 14, flexShrink: 0 }}>💡</span>
                            <p style={{ color: t.sub, fontSize: 13, margin: 0, lineHeight: 1.6 }}>{cl.suggestion}</p>
                          </div>
                        )}

                        {cl.confidence != null && (
                          <p style={{ fontSize: 11, color: t.muted, margin: 0 }}>
                            Model confidence: {Math.round(cl.confidence * 100)}%
                          </p>
                        )}
                      </div>
                    </div>
                  );
                })}
              </div>
            </Card>
          )}

          {/* Case laws */}
          {result.case_laws?.length > 0 && result.case_laws[0].title !== "IndianKanoon API key not configured" && (
            <Card t={t} style={{ marginBottom: 16 }}>
              <SectionTitle t={t}>Relevant Case Laws</SectionTitle>
              <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
                {result.case_laws.map((c, i) => (
                  <div key={i} style={{ padding: "12px 14px", borderRadius: 8, border: `1px solid ${t.border}`, background: t.surfaceUp }}>
                    <div style={{ display: "flex", justifyContent: "space-between", gap: 8, marginBottom: 4 }}>
                      <p style={{ fontWeight: 700, fontSize: 13, color: t.text, margin: 0 }}>{c.title}</p>
                      {c.year && <Tag label={c.year} variant="info" t={t} />}
                    </div>
                    {c.court   && <p style={{ fontSize: 11, color: t.muted, margin: "0 0 6px" }}>{c.court}</p>}
                    <p style={{ fontSize: 13, color: t.sub, margin: "0 0 8px", lineHeight: 1.6 }}>{c.summary}</p>
                    {c.url && (
                      <a href={c.url} target="_blank" rel="noreferrer"
                        style={{ color: t.blue, fontSize: 12, fontWeight: 600, textDecoration: "none", display: "inline-flex", alignItems: "center", gap: 4 }}>
                        View judgment <Ic d={ICONS.external} size={12} color={t.blue} />
                      </a>
                    )}
                  </div>
                ))}
              </div>
            </Card>
          )}

          {/* Q&A */}
          <Card t={t}>
            <SectionTitle t={t}>Ask about this document</SectionTitle>
            <div style={{ display: "flex", gap: 8 }}>
              <Input
                value={q} onChange={(e) => setQ(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && ask()}
                placeholder="e.g. What are the termination conditions?" t={t}
              />
              <Btn onClick={ask} disabled={qaLoad || !q} loading={qaLoad} small t={t}>
                {!qaLoad && <Ic d={ICONS.arrow} size={14} color="#fff" />}
              </Btn>
            </div>
            {ans && (
              <div style={{
                marginTop: 14, padding: "14px 16px", borderRadius: 8,
                background: t.surfaceUp, border: `1px solid ${t.border}`,
                color: t.text, fontSize: 14, lineHeight: 1.75,
              }}>
                {ans}
              </div>
            )}
          </Card>
        </>
      )}
    </div>
  );
};

export default Analyzer;
